import{c as s,cG as i,cb as a,c8 as t,cf as e,cT as l,ce as n}from"./chunks/framework.BlkIsu1j.js";const d=JSON.parse('{"title":"06. 立即数操作与移位","description":"","frontmatter":{"title":"06. 立即数操作与移位","outline":"deep","layout":"doc","prev":{"text":"05. 算术与逻辑运算","link":"/lang/assembly/05_arithmetic_logic"},"next":{"text":"07. Load 与 Store 指令","link":"/lang/assembly/07_load_store"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/06_immediates_shifts.md","filePath":"lang/assembly/06_immediates_shifts.md","lastUpdated":1780201301000}'),h={id:"frontmatter-title",tabindex:"-1"};const p=s({name:"lang/assembly/06_immediates_shifts.md"},[["render",function(s,d,p,k,r,c){return i(),a("div",null,[t("h1",h,[e(l(s.$frontmatter.title)+" ",1),d[0]||(d[0]=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),d[1]||(d[1]=n('<p>上一章介绍的 R-type 指令操作数全部来自寄存器。但在实际程序中，大量操作数是编译期已知的常量——循环步长、数组偏移、位掩码、地址对齐值。为每一个常量都先加载到寄存器再运算显然低效。RISC-V 用 I-type 指令格式将&quot;立即数&quot;直接编码在指令中，一条指令完成常量运算。</p><h2 id="i-type-指令格式" tabindex="-1">I-type 指令格式 <a class="header-anchor" href="#i-type-指令格式" aria-label="Permalink to “I-type 指令格式”">​</a></h2><p>I-type（Immediate type）将 R-type 的 funct7 + rs2 字段（共 12 位）替换为一个 12 位立即数。其他字段位置完全相同。</p><p><strong>位域布局</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌────────────────────┬───────┬─────┬───────┬─────────┐</span></span>\n<span class="line"><span>│    imm[11:0]       │  rs1  │funct3│  rd   │ opcode  │</span></span>\n<span class="line"><span>└─────────12─────────┴───5───┴──3───┴───5───┴────7────┘</span></span></code></pre></div><p>12 位立即数能表示的范围是有限的。但对于函数内部的局部常量（计数器、小偏移、常见掩码），12 位覆盖了绝大多数情况。更大的立即数用 LUI+ADDI 组合构造（第 9 章详述）。</p><h3 id="立即数的符号扩展" tabindex="-1">立即数的符号扩展 <a class="header-anchor" href="#立即数的符号扩展" aria-label="Permalink to “立即数的符号扩展”">​</a></h3><p>12 位立即数被取出后，<strong>符号扩展至 64 位</strong>才参与运算：即用 imm[11]（符号位）填充高 52 位。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>imm[11] = 0 → 高位填 0（正数或小正数）</span></span>\n<span class="line"><span>imm[11] = 1 → 高位填 1（负数）</span></span></code></pre></div><p><strong>可表示的范围</strong>（经符号扩展后）：</p><ul><li>有符号视角：[-2048, 2047]（即 -2^11 到 2^11 - 1）</li><li>无符号视角（如果指令将其视为无符号）：[0, 4095]</li></ul><p>注意：是<strong>指令语义</strong>决定将符号扩展后的值当有符号还是无符号。例如 <code>addi</code> 将其当作有符号立即数与 rs1 相加，而 <code>sltiu</code> 虽然也做符号扩展，但比较语义将其视为无符号。对于 64 位运算结果，符号扩展确保了负值立即数的数学正确性。</p><h3 id="立即数范围的硬件约束" tabindex="-1">立即数范围的硬件约束 <a class="header-anchor" href="#立即数范围的硬件约束" aria-label="Permalink to “立即数范围的硬件约束”">​</a></h3><p>为什么只给 12 位？指令总长只有 32 位——opcode（7b）+ rd（5b）+ funct3（3b）+ rs1（5b）占用 20 位，留给立即数只剩 12 位。I-type 已是在保留字段一致性的前提下最大化立即数宽度。更大的格式（U-type）给 20 位立即数，但牺牲了 rs1/rs2 字段。</p><p>实际影响：<code>addi t0, t1, 5000</code> 在汇编时报错——5000 超过 12 位有符号表示范围。此时需要用 <code>li</code> 伪指令或 <code>lui+addi</code> 手动构造：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># addi t0, t1, 5000  → 非法！立即数超出范围</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li   t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 汇编器自动展开为 lui + addi（或更优序列）</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t0, t1, t2       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = t1 + 5000</span></span></code></pre></div><h2 id="算术立即数指令" tabindex="-1">算术立即数指令 <a class="header-anchor" href="#算术立即数指令" aria-label="Permalink to “算术立即数指令”">​</a></h2><table tabindex="0"><thead><tr><th>指令</th><th>opcode</th><th>funct3</th><th>操作描述</th></tr></thead><tbody><tr><td><code>addi rd, rs1, imm</code></td><td>0010011</td><td>000</td><td>rd = rs1 + sext(imm)</td></tr><tr><td><code>slti rd, rs1, imm</code></td><td>0010011</td><td>010</td><td>rd = (rs1 &lt; sext(imm)) ? 1 : 0（有符号）</td></tr><tr><td><code>sltiu rd, rs1, imm</code></td><td>0010011</td><td>011</td><td>rd = (rs1 &lt; sext(imm)) ? 1 : 0（无符号）</td></tr></tbody></table><p>注意：I-type 算术指令的 opcode 是 <code>0010011</code>，与 R-type 的 <code>0110011</code> 不同——opcode 的第 5 位区分了寄存器操作和立即数操作。</p><h3 id="addi-的三种典型用法" tabindex="-1">addi 的三种典型用法 <a class="header-anchor" href="#addi-的三种典型用法" aria-label="Permalink to “addi 的三种典型用法”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. 寄存器 + 常量偏移</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addi t0, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # t0 = t1 + 8</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. 加载小立即数（li 伪指令的基础）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addi t0, x0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">42</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # t0 = 0 + 42 = 42 → 等效于 li t0, 42</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. 栈指针偏移（函数内局部变量访问）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addi </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 栈向下增长 16 字节</span></span></code></pre></div><p>第 3 种用法是函数序言（prologue）的核心——<code>addi sp, sp, -N</code> 分配栈帧空间，<code>addi sp, sp, N</code> 在函数尾声（epilogue）回收。</p><h3 id="为什么没有-subi" tabindex="-1">为什么没有 subi <a class="header-anchor" href="#为什么没有-subi" aria-label="Permalink to “为什么没有 subi”">​</a></h3><p>RISC-V 不设 <code>subi</code> 指令——减法等价于加负数。<code>subi rd, rs1, imm</code> 写为 <code>addi rd, rs1, -imm</code>：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 需要 t0 = t1 - 10 时：</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addi t0, t1, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 汇编器对 -10 做编码: 12 位补码 0xFF6</span></span></code></pre></div><p>汇编器在汇编阶段计算 <code>-10</code> 的 12 位补码，编码为立即数。如果 <code>imm=10</code> 的 12 位编码是 <code>0x00A</code>，<code>imm=-10</code> 的 12 位编码是 <code>0xFF6</code>——符号扩展后恰好是 -10。无需单独的 <code>subi</code> 指令，指令条数就此减少。</p><h3 id="slti-sltiu-的陷阱" tabindex="-1">slti / sltiu 的陷阱 <a class="header-anchor" href="#slti-sltiu-的陷阱" aria-label="Permalink to “slti / sltiu 的陷阱”">​</a></h3><p><code>sltiu</code> 的语义容易让人困惑——立即数先做了<strong>符号扩展</strong>，再用<strong>无符号比较 <code>rs1 &lt; sext(imm)</code></strong>。这就是为什么 <code>sltiu</code> 在比较中把 <code>sltiu t0, t1, -1</code> 的 <code>-1</code>（符号扩展后是 0xFFFFFFFFFFFFFFFF）作为极大的无符号数来比较：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li   t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slti t2, t1, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # t2 = 0（有符号 100 &lt; -1 不成立）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sltiu t3, t1, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # t3 = 1（无符号 100 &lt; 0xFFFFFFFFFFFFFFFF 成立）</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 再看一个例子：最小负数</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li   t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xFFFFFFFFFFFFFFFF</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # -1 有符号，最大值无符号</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slti t2, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x7FF</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # t2 = 1（有符号 -1 &lt; 2047 成立）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sltiu t3, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x7FF</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # t3 = 0（无符号 2^64-1 &lt; 2047 不成立）</span></span></code></pre></div><h2 id="逻辑立即数指令" tabindex="-1">逻辑立即数指令 <a class="header-anchor" href="#逻辑立即数指令" aria-label="Permalink to “逻辑立即数指令”">​</a></h2><table tabindex="0"><thead><tr><th>指令</th><th>opcode</th><th>funct3</th><th>操作描述</th></tr></thead><tbody><tr><td><code>andi rd, rs1, imm</code></td><td>0010011</td><td>111</td><td>rd = rs1 &amp; sext(imm)</td></tr><tr><td><code>ori rd, rs1, imm</code></td><td>0010011</td><td>110</td><td>rd = rs1 | sext(imm)</td></tr><tr><td><code>xori rd, rs1, imm</code></td><td>0010011</td><td>100</td><td>rd = rs1 ^ sext(imm)</td></tr></tbody></table><p>逻辑立即数指令的立即数同样做了符号扩展——但对于 AND/OR/XOR 操作，高位是 0 还是 1 对逻辑结果会有直接影响。因此使用 12 位以上的逻辑掩码时，高位由符号扩展决定：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 低 12 位全 1 → imm = 0x7FF（符号位 = 0，符号扩展后高位全 0）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">andi t0, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x7FF</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # t0 = t1 &amp; 0x0000_0000_0000_07FF（正确：只保留低 11 位）</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 低 12 位设置 bit 11 = 1 → imm = 0xFFF（符号位 = 1，符号扩展后高位全 1）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">andi t0, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xFFF</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # t0 = t1 &amp; 0xFFFF_FFFF_FFFF_FFFF（所有位都保留，等价于 NOP！）</span></span></code></pre></div><p>第二个例子是一个微妙的 bug 来源——<code>andi</code> 的立即数经符号扩展后变成全 64 位掩码，导致操作失去实际效果。需要真 12 位以上掩码时，用 <code>li</code> + R-type <code>and</code> 的方式。</p><h3 id="xori-实现-not" tabindex="-1">xori 实现 NOT <a class="header-anchor" href="#xori-实现-not" aria-label="Permalink to “xori 实现 NOT”">​</a></h3><p><code>xori rd, rs, -1</code> 等价于 <code>NOT rd, rs</code>（伪指令）。<code>-1</code> 的 12 位编码是 <code>0xFFF</code>，符号扩展后是 64 位全 1——异或全 1 = 按位取反：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">xori t0, t1, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # t0 = ~t1（每一位翻转）→ 汇编器将其展开为 not t0, t1</span></span></code></pre></div><h3 id="ori-加载无符号小立即数" tabindex="-1">ori 加载无符号小立即数 <a class="header-anchor" href="#ori-加载无符号小立即数" aria-label="Permalink to “ori 加载无符号小立即数”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ori t0, x0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xFF</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # t0 = 0 | 0x0000_0000_0000_00FF = 0xFF</span></span></code></pre></div><p>对 0-4095 范围内的无符号立即数，<code>ori rd, x0, imm</code> 是一条便捷的加载方式。不过汇编器的 <code>li</code> 伪指令通常会统一优化为最优序列——不需要手工选择 <code>addi</code> vs <code>ori</code>。</p><h2 id="移位指令" tabindex="-1">移位指令 <a class="header-anchor" href="#移位指令" aria-label="Permalink to “移位指令”">​</a></h2><p>移位指令在 RISC-V 中有两种形式：R-type（移位量在寄存器中）和 I-type（移位量是立即数）。I-type 变体用 <code>slli</code>/<code>srli</code>/<code>srai</code> 命名（末尾的 <code>i</code> 表示 immediate）。</p><h3 id="移位量编码" tabindex="-1">移位量编码 <a class="header-anchor" href="#移位量编码" aria-label="Permalink to “移位量编码”">​</a></h3><p>对于 RV64I，移位量最多 63（2^6 - 1），需要 6 位。R-type 中取自 rs2 的低 6 位（rs2[5:0]），高 58 位被忽略。I-type 中，shamt（shift amount）取自 imm[5:0]（6 位），I-type 的高 6 位 imm[11:6] 用作额外的 sub-opcode 编码：</p><table tabindex="0"><thead><tr><th>指令</th><th>opcode</th><th>funct3</th><th>imm[11:6]</th><th>操作描述</th></tr></thead><tbody><tr><td><code>slli rd, rs1, shamt</code></td><td>0010011</td><td>001</td><td>000000</td><td>rd = rs1 &lt;&lt; shamt</td></tr><tr><td><code>srli rd, rs1, shamt</code></td><td>0010011</td><td>101</td><td>000000</td><td>rd = rs1 &gt;&gt; shamt（逻辑右移，补 0）</td></tr><tr><td><code>srai rd, rs1, shamt</code></td><td>0010011</td><td>101</td><td>010000</td><td>rd = rs1 &gt;&gt; shamt（算术右移，补符号位）</td></tr></tbody></table><p>注意 <code>slli</code> 的 shamt 只有 6 位有效，I-type 立即数的高 6 位（imm[11:6]）必须是全 0——规范要求，非零值保留给未来扩展。</p><h3 id="三种移位的语义对比" tabindex="-1">三种移位的语义对比 <a class="header-anchor" href="#三种移位的语义对比" aria-label="Permalink to “三种移位的语义对比”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li   t0, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # t0 = 0xFFFF_FFFF_FFFF_FFF0</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slli t1, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 逻辑左移 2: t1 = 0xFFFF_FFFF_FFFF_FFC0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">srli t2, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 逻辑右移 2: t2 = 0x3FFF_FFFF_FFFF_FFFC（高位补 0）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">srai t3, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 算术右移 2: t3 = 0xFFFF_FFFF_FFFF_FFFC（高位补符号位 1）→ -4</span></span></code></pre></div><h3 id="移位-快速乘除" tabindex="-1">移位 = 快速乘除 <a class="header-anchor" href="#移位-快速乘除" aria-label="Permalink to “移位 = 快速乘除”">​</a></h3><p>编译器将乘/除常数优化为移位指令是常规操作。理解这一点就能读懂很多优化后的汇编：</p><table tabindex="0"><thead><tr><th>操作</th><th>移位</th><th>等价算术</th></tr></thead><tbody><tr><td><code>slli rd, rs, n</code></td><td>左移 n 位</td><td>rs * 2^n（有符号和无符号通用）</td></tr><tr><td><code>srli rd, rs, n</code></td><td>逻辑右移 n 位</td><td>rs / 2^n（无符号）</td></tr><tr><td><code>srai rd, rs, n</code></td><td>算术右移 n 位</td><td>rs / 2^n（有符号，向下取整）</td></tr></tbody></table><p><strong>有符号除法的重要差异</strong>：<code>srai</code> 的结果向负无穷取整（向下取整），而 C 语言的整数除法（<code>/</code>）向零取整。这意味着负数的移位除法结果可能与 C 代码直觉不符：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li   t0, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # t0 = -5</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">srai t1, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # t1 = -3（-5 &gt;&gt; 1 → -3，向下取整）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># C 的 -5 / 2 = -2（向零取整），所以编译器不能简单用 srai 替代有符号除法</span></span></code></pre></div><p>编译器对于 <code>x / 2^n</code>（有符号）会生成类似以下序列来纠正取整方向：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 有符号除法 x / 8（向零取整）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">srai t0, x, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">63</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 提取符号位（0 或 -1）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">srli t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">61</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # t0 = 符号位 ? 7 : 0  （2^3 - 1 = 7）</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t0, x, t0       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 负数先加上 (2^n - 1)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">srai t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 算术右移 3 位</span></span></code></pre></div><h3 id="移位组合-数组索引" tabindex="-1">移位组合：数组索引 <a class="header-anchor" href="#移位组合-数组索引" aria-label="Permalink to “移位组合：数组索引”">​</a></h3><p>移位最常见的实战场景是数组索引计算——将 C 语言的 <code>array[i]</code> 翻译为 <code>base + i * sizeof(element)</code>：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 64 位整数数组: array[i]</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 设 base 在 t0（数组基地址），index 在 t1（数组下标）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slli t2, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # t2 = index * 8（因为 sizeof(int64_t) = 8）</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t3, t0, t2      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t3 = base + index * 8 → 目标元素的地址</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ld   t4, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t3)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t4 = array[index]</span></span></code></pre></div><p><code>sizeof(element)</code> = 2^n 是常见情况（int=4 在 RV64 中、指针=8、double=8），因此 <code>slli</code> 移位量是 2 或 3 出现最多。对于非 2 的幂大小的元素（如 24 字节结构体），编译器会用乘法指令（M 扩展）或乘常数展开：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 结构体 size = 24 → 拆为 16 + 8</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slli t2, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # t2 = index * 8</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slli t3, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # t3 = index * 16</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t2, t2, t3      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t2 = index * 24</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t3, t0, t2      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t3 = base + index * 24</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ld   t4, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t3)</span></span></code></pre></div><h3 id="移位实现位域提取" tabindex="-1">移位实现位域提取 <a class="header-anchor" href="#移位实现位域提取" aria-label="Permalink to “移位实现位域提取”">​</a></h3><p>许多数据结构用位域（bitfield）打包多个小字段进一个整数。移位 + 掩码是提取和插入位域的标准手法：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从 t0 中提取 bit [15:8]（第二个字节）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">srli t1, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 右移 8 位，让目标字段到低位</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">andi t1, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xFF</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 掩码保留低 8 位</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 组合多个位域: result = (field1 &lt;&lt; 8) | field2</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slli t0, a0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # field1 左移 8 位腾出空间</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">or</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   t0, t0, a1      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 低位放入 field2</span></span></code></pre></div><h2 id="rv32-vs-rv64-的移位宽度差异" tabindex="-1">RV32 vs RV64 的移位宽度差异 <a class="header-anchor" href="#rv32-vs-rv64-的移位宽度差异" aria-label="Permalink to “RV32 vs RV64 的移位宽度差异”">​</a></h2><p>在 RV32I 中，<code>slli</code>/<code>srli</code>/<code>srai</code> 的 shamt 只有 5 位（最大移位 31），I-type imm[11:5] = 7 位编码空间用于 sub-opcode。RV64I 需要 6 位 shamt（最大移位 63），因此 I-type imm[11:6] 被赋予新的含义区分 <code>srli</code>/<code>srai</code>。</p><p>对于 R-type 移位（<code>sll</code>/<code>srl</code>/<code>sra</code>），rs2 的低位位数随 XLEN 变化：</p><ul><li>RV32：rs2[4:0]（5 位，最大移位 31）</li><li>RV64：rs2[5:0]（6 位，最大移位 63）</li></ul><p>这意味着同一个 R-type 移位指令在 RV32 和 RV64 上执行，rs2 的有效位数不同——二进制兼容的代码需要注意移位量上限。</p><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to “本章要点”">​</a></h2><ul><li>I-type 的 12 位立即数经符号扩展至 64 位参与运算——范围 [-2048, 2047]</li><li>RISC-V 不设 <code>subi</code> 和 <code>NOT</code> 专用指令——<code>addi</code> 加负数立即数和 <code>xori</code> 异或 -1 完成等价功能，减少指令总数</li><li>移位 = 快速乘除 2^n：<code>slli</code>（乘）、<code>srli</code>（无符号除）、<code>srai</code>（有符号除，向下取整）</li><li>RV64 中 I-type 移位指令的 shamt 为 6 位（imm[5:0]），imm[11:6] 区分 <code>srli</code>（000000）和 <code>srai</code>（010000）</li><li>逻辑立即数指令（andi/ori/xori）的立即数同样符号扩展——12 位以上掩码需注意符号位影响</li></ul>',70))])}]]);export{d as __pageData,p as default};
